import json
import re

# VARIABLES SHUFFLE (Lier via le bouton ⊕)
dig_raw = """$dig"""
nmap_raw = """$vuln_nmap"""
nikto_raw = """$vuln_nikto"""
ffuf_raw = """$vuln_ffuf"""
testssl_raw = """$vuln_testssl"""
zap_raw = """$owasp_zap_report"""

# Structure Master pour Flask
rapport = {
    "metadata": {
        "cible": "$exec.clean_target",
        "statut": "Audit Externe Complet",
        "total_vulns": 0
    },
    "scoring_anssi": {
        "Critique": [], "Majeur": [], "Important": [], "Mineur": []
    },
    "details_outils": {
        "nmap": [], "nikto": [], "ffuf": [], "testssl": [], "zap": [], "dig": []
    }
}

def classer_faille(gravite, outil, titre, desc, impact, exploitation, solution="A définir"):
    faille = {
        "outil": outil, "titre": titre, "description": desc,
        "impact": impact, "exploitation": exploitation, "solution": solution
    }
    # Sécurité pour éviter les erreurs de clés
    if gravite not in rapport["scoring_anssi"]: gravite = "Important"
    rapport["scoring_anssi"][gravite].append(faille)
    rapport["metadata"]["total_vulns"] += 1

# --- 1. NMAP ---
ports = re.findall(r"(\d+)/tcp\s+open\s+([\w-]+)", nmap_raw)
for p, service in ports:
    desc = f"Port {p}/TCP ouvert (Service: {service})."
    rapport["details_outils"]["nmap"].append({"port": p, "service": service})
    if p in ["22", "443", "3306"]:
        classer_faille("Important", "Nmap", f"Port sensible : {p}", desc, "Important", "Moyenne", "Filtrage IP requis")
    else:
        classer_faille("Mineur", "Nmap", f"Port ouvert : {service}", desc, "Mineur", "Difficile")

# --- 2. NIKTO ---
for ligne in nikto_raw.split('\n'):
    if "+ " in ligne:
        clean_l = ligne.strip('+ ')
        rapport["details_outils"]["nikto"].append(clean_l)
        if "config.bak" in clean_l.lower():
            classer_faille("Majeur", "Nikto", "Fichier config exposé", clean_l, "Elevé", "Facile", "Supprimer le fichier")
        elif "missing" in clean_l.lower():
            classer_faille("Mineur", "Nikto", "Header manquant", clean_l, "Faible", "Facile")

# --- 3. FFUF ---
for f in re.findall(r"(DB_.*=.*|admin.*=.*)", ffuf_raw):
    rapport["details_outils"]["ffuf"].append(f)
    classer_faille("Critique", "FFUF", "FUITE DE DONNEES BDD", f"Ligne: {f}", "Critique", "Immédiate")

# --- 4. TESTSSL ---
for ligne in testssl_raw.split('\n'):
    if "NOT ok" in ligne or "self signed" in ligne.lower():
        rapport["details_outils"]["testssl"].append(ligne.strip())
        classer_faille("Majeur", "TestSSL", "Certificat non valide", ligne.strip(), "Moyen", "Difficile")

# --- 5. OWASP ZAP (LE BLOC DE LA MORT - RÉPARÉ) ---
zap_extracted = False
try:
    # Nettoyage radical des caractères de contrôle
    zap_clean = "".join(ch for ch in zap_raw if ord(ch) >= 32 or ch in "\n\r\t")
    zap_clean = zap_clean.replace('\n', ' ').replace('\r', ' ')

    data = json.loads(zap_clean, strict=False)
    alerts = []
    if isinstance(data, dict):
        alerts = data.get("body", {}).get("alerts", []) if "body" in data else data.get("alerts", [])

    if alerts:
        for a in alerts:
            risk = a.get("risk", "Low")
            name = a.get("name", "Alerte ZAP")
            rapport["details_outils"]["zap"].append(a)
            grav = "Critique" if risk == "High" else ("Majeur" if risk == "Medium" else "Important")
            classer_faille(grav, "OWASP ZAP", name, a.get("description", "")[:150], risk, "Facile", a.get("solution"))
        zap_extracted = True

except Exception as e:
    rapport["details_outils"]["zap_error"] = f"Crash JSON : {str(e)}"

# FALLBACK : Si le JSON a crashé ou est vide, on arrache les noms par Regex
if not zap_extracted:
    # On cherche tous les patterns "name":"Le nom de la vuln"
    found_names = re.findall(r'"name"\s*:\s*"([^"]+)"', zap_raw)
    found_risks = re.findall(r'"risk"\s*:\s*"([^"]+)"', zap_raw)

    if found_names:
        for i, name in enumerate(list(set(found_names))):
            risk = found_risks[i] if i < len(found_risks) else "Medium"
            grav = "Critique" if risk == "High" else ("Majeur" if risk == "Medium" else "Important")
            classer_faille(grav, "OWASP ZAP", name, "Récupéré par extraction brute (Regex)", risk, "Facile")
            rapport["details_outils"]["zap"].append({"name": name, "risk": risk, "status": "regex_extracted"})

# --- 6. DIG ---
if "ANSWER SECTION" in dig_raw:
    ips = re.findall(r"(\d+\.\d+\.\d+\.\d+)", dig_raw)
    rapport["details_outils"]["dig"] = ips
    classer_faille("Mineur", "Dig", "Infos DNS", f"IPs: {ips}", "Faible", "Difficile")

# Final
print(json.dumps(rapport))
